  ];

  const handleAnswer = (val: string) => {
    const newAns = [...answers, val];
    if (step < questions.length - 1) {
      setAnswers(newAns);
      setStep(step + 1);
    } else {
      // Find a matching product category or just go to shop
      navigate('/shop');
