          <p className="text-2xl font-bold text-center text-slate-300">{questions[step].q}</p>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {questions[step].options.map((opt, i) => (
              <button 
                key={i} 
                onClick={() => handleAnswer(opt.value)}
                className="p-6 bg-slate-800 border-2 border-slate-700 rounded-2xl font-black text-xl hover:bg-blue-600 hover:border-blue-400 transition-all text-left flex justify-between items-center group"
