const ScentQuiz: React.FC = () => {
  const [step, setStep] = useState(0);
  const [answers, setAnswers] = useState<string[]>([]);
  const navigate = useNavigate();

  const questions = [
    {
      q: "What's your primary vibe today?",
      options: [
        { label: "Active & Energetic 🌊", value: "Fresh" },
        { label: "Dark & Mysterious 🌑", value: "Bold" },
        { label: "Sophisticated & Calm 🕯️", value: "Woody" }
      ]
    },
    {
      q: "Preferred Scent Intensity?",
      options: [
        { label: "Subtle Elegance", value: "Moderate" },
        { label: "Maximum Projection", value: "Strong" }
      ]
    }
  ];

  const handleAnswer = (val: string) => {
    const newAns = [...answers, val];
    if (step < questions.length - 1) {
      setAnswers(newAns);
      setStep(step + 1);
    } else {
      navigate('/shop');
    }
  };

  return (
    <section className="max-w-4xl mx-auto px-4 py-20 text-center">
      <div className="bg-white border-4 border-slate-900 rounded-[12px] p-10 md:p-16 shadow-[10px_10px_0px_0px_rgba(15,23,42,1)]">
        <div className="space-y-4 mb-10">
          <span className="text-blue-600 font-black text-[10px] uppercase tracking-[0.4em]">Personalized Discovery</span>
          <h2 className="text-4xl md:text-5xl font-black text-slate-900 tracking-tighter uppercase">Scent Recommendation <span className="text-blue-600">Quiz</span></h2>
        </div>

        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <p className="text-xl md:text-2xl font-black text-slate-600">{questions[step].q}</p>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {questions[step].options.map((opt, i) => (
              <button 
                key={i} 
                onClick={() => handleAnswer(opt.value)}
                className="p-6 bg-slate-50 border-4 border-slate-900 rounded-[12px] font-black text-lg hover:bg-blue-600 hover:text-white transition-all flex justify-between items-center group shadow-[4px_4px_0px_0px_rgba(15,23,42,1)] hover:shadow-none translate-x-[-2px] translate-y-[-2px] active:translate-x-0 active:translate-y-0"
              >
                {opt.label}
                <span className="opacity-0 group-hover:opacity-100 transition-opacity">→</span>
              </button>
            ))}
          </div>
          <div className="flex justify-center gap-2 pt-4">
            {questions.map((_, i) => (
              <div key={i} className={`h-2 rounded-full transition-all border border-slate-900 ${i === step ? 'w-12 bg-blue-600' : 'w-4 bg-slate-200'}`}></div>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
};

