          : 'text-slate-500 border-transparent hover:text-blue-600 hover:bg-blue-50/50'
      }`}
    >
      {label}
    </Link>
  );

  return (
    <>
      <header className={`fixed top-0 left-0 right-0 z-[60] transition-all duration-500 ${
        isScrolled ? 'py-4 translate-y-0' : 'py-8'
