import { getProductById } from '../storage';
import { Product } from '../types';

const ProductDetail: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [product, setProduct] = useState<Product | null>(null);
  const [loading, setLoading] = useState(true);

  const [watching] = useState(Math.floor(Math.random() * 24) + 6);

  useEffect(() => {
    const fetch = async () => {
      if (!id) return;
      setLoading(true);
      try {
        const p = await getProductById(id);
        if (!p) {
          navigate('/shop');
          return;
        }
        setProduct(p);
      } catch (error) {
        console.error("Error loading product details:", error);
      } finally {
        setLoading(false);
      }
    };
    fetch();
  }, [id, navigate]);

  const handleRequestAccess = () => {
    if (!product) return;
    const number = "+923700162012";
    const message = encodeURIComponent(`I am requesting private access for the ${product.name} ${product.tier || 'Series'}. 🏛️`);
    window.open(`https://wa.me/${number.replace('+', '')}?text=${message}`, '_blank');
  };

  if (loading) {
    return (
      <div className="min-h-[60vh] flex flex-col items-center justify-center space-y-4 bg-white">
        <div className="w-12 h-12 border-4 border-slate-900 border-t-transparent rounded-full animate-spin"></div>
        <p className="text-slate-400 font-black uppercase text-xs tracking-widest">Authenticating Assets...</p>
      </div>
    );
  }

  if (!product) return null;

  const specs = product.specifications || {
    topNotes: ['N/A'], middleNotes: ['N/A'], baseNotes: ['N/A'],
    longevity: 70, sillage: 'Moderate', occasions: ['General']
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-12 md:py-24 space-y-24 md:space-y-48 animate-in fade-in duration-700 bg-white selection:bg-slate-900 selection:text-white">
      <div className="flex flex-col lg:grid lg:grid-cols-2 gap-16 md:gap-32 items-start">
        {/* Left Column: Artifact Visuals */}
        <div className="w-full lg:sticky lg:top-36 space-y-12">
           <div className="aspect-[4/5] bg-slate-50 rounded-[2rem] overflow-hidden shadow-[20px_20px_0px_0px_rgba(15,23,42,0.02)] relative group border-4 border-slate-900 flex items-center justify-center">
              <img 
                src={product.imageUrl || 'https://images.unsplash.com/photo-1541643600914-78b084683601?auto=format&fit=crop&q=80&w=800'} 
                alt={product.name} 
                className="w-full h-full object-contain p-8 md:p-16 transition-transform duration-[2s] group-hover:scale-105 grayscale hover:grayscale-0" 
              />
           </div>

           <div className="grid grid-cols-2 gap-6">
              <div className="bg-slate-900 p-8 rounded-2xl text-white flex flex-col items-center text-center shadow-[8px_8px_0px_0px_rgba(15,23,42,1)] border-4 border-slate-900 transition-transform hover:-translate-y-1">
                 <span className="text-4xl mb-2">🏷️</span>
                 <p className="text-[10px] font-black uppercase tracking-widest opacity-60">Authentication</p>
                 <p className="text-xl font-black">QR Verified</p>
              </div>
              <div className="bg-white p-8 rounded-2xl text-slate-900 flex flex-col items-center text-center shadow-[8px_8px_0px_0px_rgba(15,23,42,0.1)] border-4 border-slate-900 transition-transform hover:-translate-y-1">
                 <span className="text-4xl mb-2">⚖️</span>
                 <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">Weight</p>
                 <p className="text-xl font-black uppercase">Heavy Glass</p>
              </div>
           </div>

           <div className="bg-slate-50 p-10 rounded-[2rem] border-4 border-slate-900 shadow-[8px_8px_0px_0px_rgba(15,23,42,0.05)] flex items-center justify-center gap-8 group">
              <span className="text-5xl">🗝️</span>
              <div>
                <p className="text-xl font-black text-slate-900 tracking-tighter leading-none">{watching} Collectors In-Session</p>
                <p className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-400 mt-2">Reserved Inventory Alert</p>
              </div>
           </div>
        </div>

        {/* Right Column: Narrative & Request */}
        <div className="w-full space-y-16">
          <div className="space-y-8 text-center lg:text-left">
            <div className="inline-block">
              <span className="text-slate-900 font-black text-sm uppercase tracking-[0.6em] bg-slate-50 px-8 py-3 rounded-xl border-4 border-slate-900 shadow-[6px_6px_0px_0px_rgba(15,23,42,1)]">
                {product.tier || 'The Registry'}
              </span>
            </div>
            <h1 className="text-6xl md:text-[8rem] font-black text-slate-900 tracking-tighter leading-none uppercase">{product.name}</h1>
            <p className="text-2xl md:text-4xl font-black text-slate-400 uppercase tracking-tighter leading-none">Scented Archetype № {product.id.slice(0,3).toUpperCase()}</p>

            <div className="pt-12 space-y-6">
              <h3 className="text-xl font-black uppercase tracking-[0.4em] text-slate-900">The Narrative</h3>
              <p className="text-2xl font-bold text-slate-500 leading-relaxed italic max-w-2xl">
                {product.luxuryStory || "A restricted formulation designed for those who appreciate the silence between notes. Meticulously distilled and reserved for the registry."}
              </p>
            </div>
          </div>

          {/* Luxury Attributes Block */}
          <div className="p-10 md:p-16 bg-white rounded-[3rem] border-4 border-slate-900 shadow-[20px_20px_0px_0px_rgba(15,23,42,1)] space-y-12">
            <div className="space-y-6">
              <h3 className="text-xl font-black uppercase tracking-[0.4em] text-slate-900">Artifact Specifications</h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {(product.packagingDetails || ['Engraved Batch Number', 'Weighted Magnetic Cap', 'Custom Presentation Vault', 'Ownership Certificate']).map((detail, idx) => (
                  <div key={idx} className="flex items-center gap-4 bg-slate-50 p-5 rounded-xl border-2 border-slate-100">
                    <span className="text-blue-600 text-lg">✓</span>
                    <span className="text-sm font-black uppercase tracking-widest text-slate-900">{detail}</span>
                  </div>
                ))}
              </div>
            </div>

            <div className="space-y-8 pt-12 border-t-4 border-slate-50 flex flex-col items-center">
              <div className="text-center space-y-2">
                <span className="text-4xl font-black text-slate-900 tracking-tighter leading-none">INVITATION ONLY</span>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Pricing disclosed upon registry verification</p>
              </div>
              <button 
                onClick={handleRequestAccess}
                className="w-full py-10 bg-slate-900 text-white font-black text-3xl rounded-[2rem] shadow-[15px_15px_0px_0px_rgba(15,23,42,0.1)] hover:bg-slate-800 transition-all border-4 border-slate-900 uppercase tracking-widest"
              >
                Request Private Access 🗝️
              </button>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Limited Units Available per Engraving</p>
            </div>
          </div>

          {/* Scent Journey Vertical Timeline */}
          <div className="space-y-12">
            <h3 className="text-4xl font-black tracking-tighter text-slate-900 uppercase flex items-center justify-center lg:justify-start gap-4">
              Composition <span className="text-slate-400">🧬</span>
            </h3>

            <div className="relative pl-12 space-y-16">
              <div className="absolute left-[22px] top-4 bottom-4 w-1.5 bg-slate-900 rounded-full"></div>

              <div className="relative group">
                <div className="absolute -left-[56px] top-0 w-12 h-12 rounded-full bg-white border-4 border-slate-900 flex items-center justify-center text-2xl shadow-[4px_4px_0px_0px_rgba(15,23,42,1)] z-10 group-hover:scale-110 transition-transform">🌿</div>
                <div className="bg-slate-50 p-10 rounded-[2rem] border-4 border-slate-900 shadow-[8px_8px_0px_0px_rgba(15,23,42,0.1)]">
                   <h4 className="text-2xl font-black uppercase tracking-tighter text-slate-900 mb-4">Initial Contact</h4>
                   <p className="text-slate-500 font-bold text-lg leading-relaxed">{specs.topNotes.join(' • ')}</p>
                </div>
              </div>

              <div className="relative group">
                <div className="absolute -left-[56px] top-0 w-12 h-12 rounded-full bg-slate-900 border-4 border-slate-900 flex items-center justify-center text-2xl shadow-[4px_4px_0px_0px_rgba(15,23,42,1)] z-10 group-hover:scale-110 transition-transform text-white">🌸</div>
                <div className="bg-white p-10 rounded-[2rem] border-4 border-slate-900 shadow-[8px_8px_0px_0px_rgba(15,23,42,1)]">
                   <h4 className="text-2xl font-black uppercase tracking-tighter text-slate-900 mb-4">The Heart Signature</h4>
                   <p className="text-slate-900 font-bold text-lg leading-relaxed">{specs.middleNotes.join(' • ')}</p>
                </div>
              </div>

              <div className="relative group">
                <div className="absolute -left-[56px] top-0 w-12 h-12 rounded-full bg-white border-4 border-slate-900 flex items-center justify-center text-2xl shadow-[4px_4px_0px_0px_rgba(15,23,42,1)] z-10 group-hover:scale-110 transition-transform">🌲</div>
                <div className="bg-slate-900 p-10 rounded-[2rem] border-4 border-slate-900 shadow-[8px_8px_0px_0px_rgba(15,23,42,1)] text-white">
